+    impl CaptureWriter {
+        fn new(lines: Arc<Mutex<Vec<String>>>) -> Self {
+            Self {
+                lines,
+                buffer: String::new(),
+            }
+        }
+
+        fn push_line(&self, line: &str) {
+            let trimmed = line.trim();
+            if !trimmed.is_empty() {
+                self.lines.lock().unwrap().push(trimmed.to_string());
+            }
+        }
+    }

