+                self.buffer.push_str(s);
+                while let Some(pos) = self.buffer.find('\n') {
+                    let line = self.buffer[..pos].to_string();
+                    self.buffer.drain(..=pos);
+                    self.push_line(&line);
                 }
             }
             Ok(buf.len())
         }

         fn flush(&mut self) -> std::io::Result<()> {
+            if !self.buffer.is_empty() {
